const items = $input.all();
return items.map(item => {
  const binaryData = item.binary.data;
  return {
    json: {
      fileId: item.json.id,
      fileName: binaryData.fileName || item.json.name,
      mimeType: binaryData.mimeType,
      base64: binaryData.data,
      webViewLink: item.json.webViewLink
    }
  };
});

const response = $input.first().json;
const meta = $node["Préparer Base64 & Métadonnées"].json;

let text = '';
try {
  text = response.candidates[0].content.parts[0].text;
} catch (e) {
  text = '{}';
}
text = text.trim().replace(/^```json/i, '').replace(/^```/, '').replace(/```$/, '').trim();

let facture;
try {
  facture = JSON.parse(text);
} catch (e) {
  facture = { erreur_parsing: true, texte_brut: text };
}

return [{
  json: {
    ...facture,
    fileId: meta.fileId,
    fileName: meta.fileName,
    webViewLink: meta.webViewLink
  }
}];

const facture = $input.first().json;
const erreurs = [];
const avertissements = [];

const ht = parseFloat(facture.montant_ht);
const tva = parseFloat(facture.montant_tva);
const ttc = parseFloat(facture.montant_ttc);
const taux = parseFloat(facture.taux_tva);
const ice = (facture.ice || '').toString().replace(/\s/g, '');
const nature = (facture.nature_operation || '').toLowerCase();

// 1. Controle mathematique HT + TVA = TTC
if (!isNaN(ht) && !isNaN(tva) && !isNaN(ttc)) {
  const ecart = Math.abs((ht + tva) - ttc);
  if (ecart > 0.5) {
    erreurs.push('Erreur de calcul : HT (' + ht + ') + TVA (' + tva + ') = ' + (ht + tva).toFixed(2) + ' ne correspond pas au TTC declare (' + ttc + ')');
  }
} else {
  erreurs.push('Montants HT, TVA ou TTC illisibles ou manquants');
}

// 2. Controle coherence taux vs montant TVA
if (!isNaN(ht) && !isNaN(taux) && !isNaN(tva)) {
  const tvaTheorique = ht * taux / 100;
  if (Math.abs(tvaTheorique - tva) > 0.5) {
    erreurs.push('Le montant de TVA (' + tva + ') ne correspond pas au taux applique (' + taux + '%) sur le HT (' + ht + '). TVA attendue : ' + tvaTheorique.toFixed(2));
  }
}

// 3. Controle ICE (15 chiffres)
if (!/^\d{15}$/.test(ice)) {
  erreurs.push('ICE invalide : ' + (ice || 'absent') + ' (doit contenir exactement 15 chiffres)');
}

// 4. Controle coherence taux TVA / nature operation (regles Maroc, indicatif)
const tauxAttendus = {
  transport: 14, energie: 14, petrole: 14, carburant: 14,
  restauration: 10, hebergement: 10, hotellerie: 10, banque: 10, credit: 10,
  eau: 7, electricite: 7,
  export: 0, exonere: 0
};
for (const cle in tauxAttendus) {
  if (nature.includes(cle)) {
    if (!isNaN(taux) && taux !== tauxAttendus[cle]) {
      avertissements.push('Taux de TVA (' + taux + '%) inhabituel pour une operation de type \'' + cle + '\' (taux courant attendu : ' + tauxAttendus[cle] + '%). A verifier.');
    }
  }
}
const tauxValides = [0, 7, 10, 14, 20];
if (!isNaN(taux) && !tauxValides.includes(taux)) {
  erreurs.push('Taux de TVA non standard au Maroc : ' + taux + '%');
}

return [{
  json: {
    ...facture,
    validation: {
      erreurs,
      avertissements,
      controle_mathematique_ok: erreurs.length === 0
    }
  }
}];

const facture = $node["Contrôle Fiscal & Mathématique"].json;
const historique = $input.all().map(i => i.json).filter(r => r && Object.keys(r).length > 0);

return [{
  json: {
    facture,
    historique
  }
}];

const response = $input.first().json;
const facture = $node["Agréger Historique"].json.facture;

let text = '';
try {
  text = response.candidates[0].content.parts[0].text;
} catch (e) {
  text = '{}';
}
text = text.trim().replace(/^```json/i, '').replace(/^```/, '').replace(/```$/, '').trim();

let anomalie;
try {
  anomalie = JSON.parse(text);
} catch (e) {
  anomalie = { anomalie_detectee: false, type_anomalie: null, niveau_risque: 'faible', explication: 'Analyse IA indisponible' };
}

return [{
  json: {
    ...anomalie,
    facture
  }
}];

const anomalie = $input.first().json;
const facture = anomalie.facture;
const validation = facture.validation || { erreurs: [], avertissements: [] };

const erreursFinales = [...validation.erreurs];
if (anomalie.anomalie_detectee && anomalie.niveau_risque !== 'faible') {
  erreursFinales.push('Anomalie IA detectee (risque ' + anomalie.niveau_risque + ') : ' + anomalie.explication);
}

const statut = erreursFinales.length === 0 ? 'VALIDE' : 'ANOMALIE';

return [{
  json: {
    ...facture,
    anomalie_ia: {
      anomalie_detectee: anomalie.anomalie_detectee,
      type_anomalie: anomalie.type_anomalie,
      niveau_risque: anomalie.niveau_risque,
      explication: anomalie.explication
    },
    statut,
    erreurs_finales: erreursFinales,
    avertissements: validation.avertissements
  }
}];
